using UnityEngine;
using Climbing;

public class ClimbRefChecker
{
    public static string Check()
    {
        GameObject pm = GameObject.Find("Player_New/PlayerModel");
        if (pm == null) return "PlayerModel not found";
        ClimbController cc = pm.GetComponent<ClimbController>();
        if (cc == null) return "ClimbController not found";

        string lHand = cc.LHand != null ? cc.LHand.name : "NULL";
        string rHand = cc.RHand != null ? cc.RHand.name : "NULL";
        string lFoot = cc.LFoot != null ? cc.LFoot.name : "NULL";
        string rFoot = cc.RFoot != null ? cc.RFoot.name : "NULL";

        return $"LHand: {lHand}, RHand: {rHand}, LFoot: {lFoot}, RFoot: {rFoot}";
    }
}
